import (
	"context"
	"fmt"

	"github.com/openmeterio/openmeter/openmeter/billing/charges/lineage"
	"github.com/openmeterio/openmeter/pkg/clock"
	"github.com/openmeterio/openmeter/pkg/framework/transaction"
)

func (s *service) MyNewMutation(ctx context.Context, input lineage.MyInput) error {
	if err := input.Validate(); err != nil {
		return err
	}

	return transaction.RunWithNoValue(ctx, s.adapter, func(ctx context.Context) error {
		// 1. Lock before reading
		lineages, err := s.adapter.LockCorrectionLineages(ctx, input.Namespace, input.IDs)
		if err != nil {
			return fmt.Errorf("lock lineages: %w", err)
		}

		now := clock.Now().Truncate(time.Microsecond)

		for _, seg := range lineages[0].Segments {
			// 2. Close then split
			if err := s.adapter.CloseSegment(ctx, seg.ID, now); err != nil {
				return err
			}
			// create new segment(s) as needed
		}
		return nil
	})
}
